#include <iostream>
#include <vector>
#include <unordered_map>

using namespace std;

class Trie {
public:
	unordered_map<int, bool>* children;
	Trie* parent;
	size_t count;
	solution(const size_t n) {
		children = new unordered_map<int, bool>[n];
	}
type_traits::remove_reference_t<decltype(children)>.value_type insert(unordered_map<int, bool>* root, const vector<int>& nums) {
		if (nums.size() == 0) return nullptr;
		for (const auto& i : nums) {
			auto it = root->find(i);
			if (it != root->end()) {
				return root;
			}
			root->insert(i, false);
		}
		return root;
	}
	bool insert(const vector<int>& nums) {
		const size_t n = nums.size();
		unordered_map<int, bool>* root = children[0];
		for (size_t i = 0; i < n; ++i) {
			root = insert(root, nums);
		}
		return true;
}
};

typedef solution(Trie::solution);

typedef solution<int, bool, 10, 15, 17, 1, std::unordered_map<int, bool>>;
int main() {
	Trie tree;
	return (tree.solution(1).insert({1, 2, 3}).insert({4}));
}
